function updateStats(){
  var total=0,done=0;
  CHAPTERS.forEach(function(ch){total+=10;done+=chDone(ch);});
  document.getElementById('stats').innerHTML=
    CHAPTERS.length+' chapters &bull; '+done+'/'+total+' clips done<br>'+(total-done)+' clips remaining';
